  "privacyPolicy.collectEmailWhy": "Login, one-time passcodes (OTP) and service notifications",
  "privacyPolicy.collectPasswordLabel": "Password",
  "privacyPolicy.collectPasswordWhy": "Account security — stored only as a salted hash, never in plain text",
  "privacyPolicy.collectPhoneLabel": "Phone number",
  "privacyPolicy.collectPhoneWhy": "So our agents can contact you about a pickup or delivery",
  "privacyPolicy.collectAddressLabel": "Pickup / delivery addresses",
  "privacyPolicy.collectAddressWhy": "To collect and return your laundry",
