  "privacyPolicy.collectOrdersLabel": "Orders, requests & reviews",
  "privacyPolicy.collectOrdersWhy": "To fulfil your orders and improve the service",
  "privacyPolicy.useInfoTitle": "How we use your information",
  "privacyPolicy.useInfoBullet1": "To create and secure your account and sign you in.",
  "privacyPolicy.useInfoBullet2": "To send one-time passcodes and essential service emails.",
  "privacyPolicy.useInfoBullet3": "To schedule, fulfil and deliver your laundry orders.",
  "privacyPolicy.useInfoBullet4": "To let delivery agents complete assigned requests.",
  "privacyPolicy.useInfoBullet5": "To operate, maintain, debug and improve the app.",
  "privacyPolicy.useInfoBullet6": "To respond to your support requests.",
  "privacyPolicy.useInfoFooter": "We do not sell your personal data, and we do not use it for third-party advertising.",
  "privacyPolicy.sharingTitle": "How your data is shared",
  "privacyPolicy.sharingIntro": "We share data only with service providers that help us run Clean Pro, and only as needed:",
  "privacyPolicy.sharingBullet1": "MongoDB Atlas — secure database hosting for your account and order data.",
  "privacyPolicy.sharingBullet2": "Render — hosting for our backend service.",
  "privacyPolicy.sharingBullet3": "Google (Gmail) — to deliver one-time passcode and notification emails.",
  "privacyPolicy.sharingBullet4": "Sentry — crash diagnostics, configured to exclude your personal data.",
  "privacyPolicy.crashTitle": "Crash and error reporting",
  "privacyPolicy.crashPara1": "To keep the app stable we record diagnostic information when an error occurs (error message, screen, device model, OS and app version). This is configured to not attach personal identifying information such as your email.",
  "privacyPolicy.retentionTitle": "Data retention",
  "privacyPolicy.retentionPara1": "We keep your personal data while your account is active. When you ask us to delete your account, we remove your personal data within 30 days, except where we must keep limited records to meet legal obligations.",
  "privacyPolicy.rightsTitle": "Your rights and choices",
  "privacyPolicy.rightsBullet1": "Access or update your profile information from within the app.",
  "privacyPolicy.rightsBullet2": "Delete your account and personal data by contacting us.",
  "privacyPolicy.rightsBullet3": "Withdraw consent for optional data (e.g. remove your profile photo) at any time.",
  "privacyPolicy.securityTitle": "Data security",
  "privacyPolicy.securityBullet1": "Passwords are stored only as salted bcrypt hashes.",
  "privacyPolicy.securityBullet2": "Sessions use short-lived access tokens and rotating refresh tokens.",
  "privacyPolicy.securityBullet3": "Traffic between the app and our servers is encrypted over HTTPS.",
  "privacyPolicy.securityBullet4": "Access to production data is restricted.",
  "privacyPolicy.childrenTitle": "Children's privacy",
  "privacyPolicy.childrenPara1": "Clean Pro is not directed to children under 13. We do not knowingly collect data from children. If you believe a child has provided us data, contact us and we will delete it.",
